import java.sql.*;

public class VulnerableCode {
    public static void main(String[] args) {
        try {
            String username = "admin'; --";
            String password = "password123";

            // Vulnerable code - concatenating user input directly into the SQL query
            String query = "SELECT * FROM users WHERE username='" + username + "' AND password='" + password + "'";

            // Connecting to database (assuming a SQLite database for this example)
            Connection conn = DriverManager.getConnection("jdbc:sqlite:/path/to/database.db");
