import java.sql.*;

public class SecureCode {
    public static void main(String[] args) {
        try {
            String username = "admin'; --"; // User input
            String password = "password123"; // User input

            String query = "SELECT * FROM users WHERE username=? AND password=?";

            // Connecting to database (assuming a SQLite database for this example)
            Connection conn = DriverManager.getConnection("jdbc:sqlite:/path/to/database.db");

            PreparedStatement pstmt = conn.prepareStatement(query);
            pstmt.setString(1, username);
            pstmt.setString(2, password);

            ResultSet rs = pstmt.executeQuery();

            if (rs.next()) {
                System.out.println("Login successful!");
            } else {
                System.out.println("Login failed!");
            }

            conn.close();
        } catch (SQLException e) {
            System.err.println("An error occurred: " + e.getMessage());
        }
    }
}

